#include <stdio.h>
#include <string.h>
#define MAXN 256
#define MAXK 32
int dp[MAXN + 1][MAXK + 1];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char S[MAXN + 1];
        scanf("%s", S);
        // Initialize dp array
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = dp[i - 1][j];
                if (S[i - 1] == 'c') {
                    dp[i][j] += dp[i - 1][j];
                } else if (S[i - 1] == 'h') {
                    dp[i][j] += dp[i - 1][j];
                } else if (S[i - 1] == 'e') {
                    dp[i][j] += dp[i - 1][j];
                } else if (S[i - 1] == 'f') {
                    dp[i][j] += dp[i - 1][j];
                }
            }
        }
        int ans = -1;
        for (int i = 0; i <= N; i++) {
            if (dp[i][K] > 0) {
                ans = N - i;
                break;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

