        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String S = sc.next();
            int[][] dp = new int[N + 1][K + 1];
            // Initialize dp array
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    dp[i][j] = 0;
                }
            }
            dp[0][0] = 1;
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    dp[i][j] = dp[i - 1][j];
                    if (S.charAt(i - 1) == 'c') {
                        dp[i][j] += dp[i - 1][j];
                    } else if (S.charAt(i - 1) == 'h') {
                        dp[i][j] += dp[i - 1][j];
                    } else if (S.charAt(i - 1) == 'e') {
                        dp[i][j] += dp[i - 1][j];
                    } else if (S.charAt(i - 1) == 'f') {
                        dp[i][j] += dp[i - 1][j];
                    }
                }
            }
            int ans = -1;
            for (int i = 0; i <= N; i++) {
                if (dp[i][K] > 0) {
